import{_ as a,o as e,c as i,ai as t}from"./chunks/framework.CsYGeNYI.js";const k=JSON.parse('{"title":"控制 UI","description":"","frontmatter":{"read_when":["你想从浏览器操作 Gateway 网关","你想要无需 SSH 隧道的 Tailnet 访问"],"summary":"Gateway 网关的浏览器控制 UI（聊天、节点、配置）","title":"控制 UI","x-i18n":{"generated_at":"2026-02-03T10:13:20Z","model":"claude-opus-4-5","provider":"pi","source_hash":"bef105a376fc1a1df44e3e4fb625db1cbcafe2f41e718181c36877b8cbc08816","source_path":"web/control-ui.md","workflow":15}},"headers":[],"relativePath":"zh-CN/web/control-ui.md","filePath":"zh-CN/web/control-ui.md","lastUpdated":null}'),l={name:"zh-CN/web/control-ui.md"};function n(o,s,p,d,c,h){return e(),i("div",null,[...s[0]||(s[0]=[t(`<h1 id="控制-ui-浏览器" tabindex="-1"><a class="header-anchor" href="#控制-ui-浏览器">#</a> 控制 UI（浏览器）</h1><p>控制 UI 是一个由 Gateway 网关提供服务的小型 <strong>Vite + Lit</strong> 单页应用：</p><ul><li>默认：<code>http://&lt;host&gt;:18789/</code></li><li>可选前缀：设置 <code>gateway.controlUi.basePath</code>（例如 <code>/opensoul</code>）</li></ul><p>它<strong>直接与同一端口上的 Gateway 网关 WebSocket</strong> 通信。</p><h2 id="快速打开-本地" tabindex="-1"><a class="header-anchor" href="#快速打开-本地">#</a> 快速打开（本地）</h2><p>如果 Gateway 网关在同一台计算机上运行，打开：</p><ul><li><a href="http://127.0.0.1:18789/%EF%BC%88%E6%88%96" target="_blank" rel="noreferrer">http://127.0.0.1:18789/（或</a> <code>http://localhost:18789/</code>）</li></ul><p>如果页面加载失败，请先启动 Gateway 网关：<code>opensoul gateway</code>。</p><p>认证在 WebSocket 握手期间通过以下方式提供：</p><ul><li><code>connect.params.auth.token</code></li><li><code>connect.params.auth.password</code> 仪表板设置面板允许你存储 token；密码不会被持久化。 新手引导向导默认生成一个 Gateway 网关 token，所以在首次连接时将其粘贴到这里。</li></ul><h2 id="设备配对-首次连接" tabindex="-1"><a class="header-anchor" href="#设备配对-首次连接">#</a> 设备配对（首次连接）</h2><p>当你从新浏览器或设备连接到控制 UI 时，Gateway 网关需要<strong>一次性配对批准</strong> — 即使你在同一个 Tailnet 上且 <code>gateway.auth.allowTailscale: true</code>。这是防止未授权访问的安全措施。</p><p><strong>你会看到：</strong> &quot;disconnected (1008): pairing required&quot;</p><p><strong>批准设备：</strong></p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 列出待处理的请求</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> devices</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> list</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 按请求 ID 批准</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> devices</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> approve</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">requestI</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">d</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>一旦批准，设备会被记住，除非你使用 <code>opensoul devices revoke --device &lt;id&gt; --role &lt;role&gt;</code> 撤销它，否则不需要重新批准。参见 <a href="/docs/cli/devices">Devices CLI</a> 了解 token 轮换和撤销。</p><p><strong>注意：</strong></p><ul><li>本地连接（<code>127.0.0.1</code>）会自动批准。</li><li>远程连接（LAN、Tailnet 等）需要显式批准。</li><li>每个浏览器配置文件生成唯一的设备 ID，因此切换浏览器或清除浏览器数据将需要重新配对。</li></ul><h2 id="目前可以做什么" tabindex="-1"><a class="header-anchor" href="#目前可以做什么">#</a> 目前可以做什么</h2><ul><li>通过 Gateway 网关 WS 与模型聊天（<code>chat.history</code>、<code>chat.send</code>、<code>chat.abort</code>、<code>chat.inject</code>）</li><li>在聊天中流式传输工具调用 + 实时工具输出卡片（智能体事件）</li><li>渠道：WhatsApp/Telegram/Discord/Slack + 插件渠道（Mattermost 等）状态 + QR 登录 + 每渠道配置（<code>channels.status</code>、<code>web.login.*</code>、<code>config.patch</code>）</li><li>实例：在线列表 + 刷新（<code>system-presence</code>）</li><li>会话：列表 + 每会话思考/详细覆盖（<code>sessions.list</code>、<code>sessions.patch</code>）</li><li>定时任务：列出/添加/运行/启用/禁用 + 运行历史（<code>cron.*</code>）</li><li>Skills：状态、启用/禁用、安装、API 密钥更新（<code>skills.*</code>）</li><li>节点：列表 + 能力（<code>node.list</code>）</li><li>执行批准：编辑 Gateway 网关或节点允许列表 + <code>exec host=gateway/node</code> 的询问策略（<code>exec.approvals.*</code>）</li><li>配置：查看/编辑 <code>~/.opensoul/opensoul.json</code>（<code>config.get</code>、<code>config.set</code>）</li><li>配置：应用 + 带验证的重启（<code>config.apply</code>）并唤醒上次活动的会话</li><li>配置写入包含基础哈希保护，以防止覆盖并发编辑</li><li>配置 schema + 表单渲染（<code>config.schema</code>，包括插件 + 渠道 schema）；原始 JSON 编辑器仍然可用</li><li>调试：状态/健康/模型快照 + 事件日志 + 手动 RPC 调用（<code>status</code>、<code>health</code>、<code>models.list</code>）</li><li>日志：Gateway 网关文件日志的实时尾部跟踪，带过滤/导出（<code>logs.tail</code>）</li><li>更新：运行包/git 更新 + 重启（<code>update.run</code>）并显示重启报告</li></ul><h2 id="聊天行为" tabindex="-1"><a class="header-anchor" href="#聊天行为">#</a> 聊天行为</h2><ul><li><code>chat.send</code> 是<strong>非阻塞的</strong>：它立即以 <code>{ runId, status: &quot;started&quot; }</code> 确认，响应通过 <code>chat</code> 事件流式传输。</li><li>使用相同的 <code>idempotencyKey</code> 重新发送在运行时返回 <code>{ status: &quot;in_flight&quot; }</code>，完成后返回 <code>{ status: &quot;ok&quot; }</code>。</li><li><code>chat.inject</code> 将助手备注附加到会话转录，并为仅 UI 更新广播 <code>chat</code> 事件（无智能体运行，无渠道投递）。</li><li>停止： <ul><li>点击<strong>停止</strong>（调用 <code>chat.abort</code>）</li><li>输入 <code>/stop</code>（或 <code>stop|esc|abort|wait|exit|interrupt</code>）以带外中止</li><li><code>chat.abort</code> 支持 <code>{ sessionKey }</code>（无 <code>runId</code>）以中止该会话的所有活动运行</li></ul></li></ul><h2 id="tailnet-访问-推荐" tabindex="-1"><a class="header-anchor" href="#tailnet-访问-推荐">#</a> Tailnet 访问（推荐）</h2><h3 id="集成-tailscale-serve-首选" tabindex="-1"><a class="header-anchor" href="#集成-tailscale-serve-首选">#</a> 集成 Tailscale Serve（首选）</h3><p>保持 Gateway 网关在 loopback 上，让 Tailscale Serve 用 HTTPS 代理它：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gateway</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --tailscale</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> serve</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>打开：</p><ul><li><code>https://&lt;magicdns&gt;/</code>（或你配置的 <code>gateway.controlUi.basePath</code>）</li></ul><p>默认情况下，当 <code>gateway.auth.allowTailscale</code> 为 <code>true</code> 时，Serve 请求可以通过 Tailscale 身份头（<code>tailscale-user-login</code>）进行认证。OpenSoul 通过使用 <code>tailscale whois</code> 解析 <code>x-forwarded-for</code> 地址并与头匹配来验证身份，并且只在请求通过 Tailscale 的 <code>x-forwarded-*</code> 头到达 loopback 时接受这些。如果你想即使对于 Serve 流量也要求 token/密码，请设置 <code>gateway.auth.allowTailscale: false</code>（或强制 <code>gateway.auth.mode: &quot;password&quot;</code>）。</p><h3 id="绑定到-tailnet-token" tabindex="-1"><a class="header-anchor" href="#绑定到-tailnet-token">#</a> 绑定到 tailnet + token</h3><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gateway</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --bind</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tailnet</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --token</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;$(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openssl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> rand </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">-hex</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 32</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">)&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>然后打开：</p><ul><li><code>http://&lt;tailscale-ip&gt;:18789/</code>（或你配置的 <code>gateway.controlUi.basePath</code>）</li></ul><p>将 token 粘贴到 UI 设置中（作为 <code>connect.params.auth.token</code> 发送）。</p><h2 id="不安全的-http" tabindex="-1"><a class="header-anchor" href="#不安全的-http">#</a> 不安全的 HTTP</h2><p>如果你通过普通 HTTP 打开仪表板（<code>http://&lt;lan-ip&gt;</code> 或 <code>http://&lt;tailscale-ip&gt;</code>），浏览器在<strong>非安全上下文</strong>中运行并阻止 WebCrypto。默认情况下，OpenSoul <strong>阻止</strong>没有设备身份的控制 UI 连接。</p><p><strong>推荐修复：</strong> 使用 HTTPS（Tailscale Serve）或在本地打开 UI：</p><ul><li><code>https://&lt;magicdns&gt;/</code>（Serve）</li><li><code>http://127.0.0.1:18789/</code>（在 Gateway 网关主机上）</li></ul><p><strong>降级示例（仅通过 HTTP 使用 token）：</strong></p><div class="language-json5 vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">json5</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  gateway</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    controlUi</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: { </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">allowInsecureAuth</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> },</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    bind</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;tailnet&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    auth</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: { </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">mode</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;token&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">token</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;replace-me&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> },</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  },</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>这会为控制 UI 禁用设备身份 + 配对（即使在 HTTPS 上）。仅在你信任网络时使用。</p><p>参见 <a href="/docs/gateway/tailscale">Tailscale</a> 了解 HTTPS 设置指南。</p><h2 id="构建-ui" tabindex="-1"><a class="header-anchor" href="#构建-ui">#</a> 构建 UI</h2><p>Gateway 网关从 <code>dist/control-ui</code> 提供静态文件。使用以下命令构建：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ui:build</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 首次运行时自动安装 UI 依赖</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>可选的绝对基础路径（当你想要固定的资源 URL 时）：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">OPENSOUL_CONTROL_UI_BASE_PATH</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/opensoul/</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ui:build</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>用于本地开发（单独的开发服务器）：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ui:dev</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 首次运行时自动安装 UI 依赖</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>然后将 UI 指向你的 Gateway 网关 WS URL（例如 <code>ws://127.0.0.1:18789</code>）。</p><h2 id="调试-测试-开发服务器-远程-gateway-网关" tabindex="-1"><a class="header-anchor" href="#调试-测试-开发服务器-远程-gateway-网关">#</a> 调试/测试：开发服务器 + 远程 Gateway 网关</h2><p>控制 UI 是静态文件；WebSocket 目标是可配置的，可以与 HTTP 源不同。当你想要在本地使用 Vite 开发服务器但 Gateway 网关在其他地方运行时，这很方便。</p><ol><li>启动 UI 开发服务器：<code>pnpm ui:dev</code></li><li>打开类似以下的 URL：</li></ol><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>http://localhost:5173/?gatewayUrl=ws://&lt;gateway-host&gt;:18789</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>可选的一次性认证（如需要）：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>http://localhost:5173/?gatewayUrl=wss://&lt;gateway-host&gt;:18789&amp;token=&lt;gateway-token&gt;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>注意：</p><ul><li><code>gatewayUrl</code> 在加载后存储在 localStorage 中并从 URL 中移除。</li><li><code>token</code> 存储在 localStorage 中；<code>password</code> 仅保留在内存中。</li><li>当 Gateway 网关在 TLS 后面时（Tailscale Serve、HTTPS 代理等），使用 <code>wss://</code>。</li></ul><p>远程访问设置详情：<a href="/docs/gateway/remote">远程访问</a>。</p>`,59)])])}const g=a(l,[["render",n]]);export{k as __pageData,g as default};
